import{c as t,Q as a,j as r,m as o}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"君主论第25章 · 现代批注","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/commentary/ch25-prince.md","filePath":"research/machiavelli/commentary/ch25-prince.md"}'),c={name:"research/machiavelli/commentary/ch25-prince.md"};function p(n,e,i,s,l,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="君主论第25章-·-现代批注" tabindex="-1">君主论第25章 · 现代批注 <a class="header-anchor" href="#君主论第25章-·-现代批注" aria-label="Permalink to &quot;君主论第25章 · 现代批注&quot;">​</a></h1><blockquote><p>马基雅维利本人对本章的 500 字现代重读。保留直截了当、警句式的文风。</p></blockquote><hr><p>人们总是低估运气。他们觉得努力就能成功，规划就能成事——这就像在湍急的河边盖房子而不修堤坝。风平浪静时，一切安好；洪水一来，连地基都被卷走。</p><p>我在第25章说的是：机运控制大约一半的人事，我们控制另一半。注意这个&quot;大约&quot;——我不是在给你一个精确的数字，我是在提醒你，不要把比例搞反。太多人以为他们能控制八分、九分，结果灾难来临时措手不及。</p><p>在你们的时代，这听起来像是创业者在第三轮融资后说的&quot;一切都是我的能力&quot;。然后市场崩了。然后他们才发现，原来运气也参与了一半。</p><p>但更关键的是我不会让步的那一半：你仍然有修筑堤坝的空间。你仍然可以——在风平浪静时——建立自己的专业能力、储备资源、培养人脉。区别在于：你不做这些，洪水来了就完了；你做了，洪水来了你还有选择。</p><p>第25章最险的一句话是最后那句：&quot;同女人一样，机运始终是年轻人的朋友。&quot;我那个时代的读者以为我在写性。我在写的是另一个东西：大胆胜过谨慎。不是粗暴，是大胆。年轻人不太计算得失，因此更愿意出手。老了的人算得太清楚，等待完美的时机——完美的时机永远不会来。</p><p>记得尤利乌斯二世吗？他做了什么？所有数字都显示他不能成功的行动。他没有等待。他让所有人大吃一惊。想要证明自己是对的最可靠方法，就是先动。不是蛮干——但如果你永远等待所有条件凑齐，你会死在等待中。</p><p>运气的残酷在于，它会给你足够多的东西，让你舒服到失去警惕。真正的敌人不是你差一点就能拥有的机会，而是你已经拥有的安全感。在风平浪静时修建堤坝，比洪水到来时叫喊&quot;不公&quot;更有用。</p>',10)])])}const u=t(c,[["render",p]]);export{h as __pageData,u as default};
